/* * * V i t a l s * * */
import * as React from 'react';
import APIaccess from '../../apiaccess';
import Log from '../Log/Log';
import './Home.css';
import FullList from '../../components/base/fullList';

let accessAPI = APIaccess();

export default function UserLog({active, setCurrent, current, log, setLog, sectionClass, refe}) {

	// let [place, setPlace] = React.useState(active == 1 || active == null ? '' : 'not');
	let userID = sessionStorage.getItem('userID');
	let [isModal, openModal] = React.useReducer(state => !state, false);

	let updateLog = async() => {

		let posts = await accessAPI.pullUserLog({type: 'customLog', logNumber: current.log})
		setLog(posts);
	} 

	React.useEffect(()=> {
		updateLog()
		// setCurrent({
		// 	...current,
		// 	social: false
		// })
	}, [])

	React.useEffect(()=> {
		updateLog()
	}, [current.modal, current.customizer])

	let noHeading = false;

	return (
		<div id="userLog" className={ `${sectionClass.home}` } ref={refe}>
			<Log data={log} 
				 section={"user"} 
				 noHeading={noHeading} 
				 current={current} 
				 setCurrent={setCurrent}
				 updateLog={updateLog}/>
		</div>
	)
}
